const fs = require('fs');

const filePath = 'path/to/your/file.ext';

fs.stat(filePath, (err, stats) => {
    if (err) {
        console.error('Error fetching file stats:', err);
        return;
    }

    const fileSizeInMB = stats.size / (1024 * 1024); // Convert bytes to MB
    const creationDate = stats.birthtime; // File creation time

